import React, { useState } from "react";
import { useCart } from "./CartContext";
import { useNavigate } from "react-router-dom";

function Help() {
  const {
    cartItems,
    addToCart,
    increaseQty,
    decreaseQty
  } = useCart();

  const navigate = useNavigate();

  const [activeService, setActiveService] = useState(null);
  const [message, setMessage] = useState("");

  const services = [
    "Medicines",
    "Groceries",
    "Emergency",
    "Food Delivery",
    "Transport"
  ];

  // ✅ MATCH DB IDs + ADD PRICE + STOCK
  const medicines = [
    { id: 1, name: "Paracetamol", price: 20, stock: 87 },
    { id: 2, name: "Ibuprofen", price: 35, stock: 100 },
    { id: 3, name: "Amoxicillin", price: 60, stock: 99 },
    { id: 4, name: "Cetirizine", price: 15, stock: 98 },
    { id: 5, name: "Vitamin C", price: 25, stock: 100 }
  ];

  const getQty = (id) => {
    const item = cartItems.find((i) => i.id === id);
    return item ? item.quantity : 0;
  };

  const totalItems = cartItems.reduce((s, i) => s + i.quantity, 0);

  return (
    <div className="help-container">

      {/* 🔝 HEADER WITH CART */}
      <div className="help-header">
        <h2>Services</h2>

        <div className="cart-icon" onClick={() => navigate("/cart")}>
          🛒 {totalItems > 0 && <span className="badge">{totalItems}</span>}
        </div>
      </div>

      {/* 🔥 SERVICES */}
      <div className="services-row">
        {services.map((service) => (
          <div
            key={service}
            className={`service-box ${
              activeService === service ? "active" : ""
            }`}
            onClick={() => {
              setActiveService(service);

              if (service !== "Medicines") {
                setMessage(service + " service is under maintenance 🚧");
              } else {
                setMessage("");
              }
            }}
          >
            {service}
          </div>
        ))}
      </div>

      {/* ⚠️ MESSAGE ON PAGE */}
      {message && (
        <p className="maintenance-msg">{message}</p>
      )}

      {/* 💊 MEDICINES */}
      {activeService === "Medicines" && (
        <div className="medicine-vertical">

          {medicines.map((med) => {
            const qty = getQty(med.id);

            return (
              <div key={med.id} className="medicine-card">

                <div>
                  <h4>{med.name}</h4>
                  <p>₹{med.price}</p>
                  <small>Stock: {med.stock}</small>
                </div>

                {qty === 0 ? (
                  <button
                    className="add-btn"
                    onClick={() => addToCart(med)}
                  >
                    Add
                  </button>
                ) : (
                  <div className="qty-controls">
                    <button onClick={() => decreaseQty(med.id)}>-</button>
                    <span>{qty}</span>
                    <button
                      onClick={() => increaseQty(med.id)}
                      disabled={qty >= 5}
                    >
                      +
                    </button>
                  </div>
                )}

              </div>
            );
          })}

        </div>
      )}

    </div>
  );
}

export default Help;
